   115  // Object interface generated from "k8s:prerelease-lifecycle-gen:introduced" tags in types.go.
   116  type introducedInterface interface {
   117          APILifecycleIntroduced() (major, minor int)
   118  }
   119
   120  type replacementInterface interface {
   121          APILifecycleReplacement() schema.GroupVersionKind
   122  }
   123
   124  func emulatedStorageVersion(binaryVersionOfResource schema.GroupVersion, example runtime.Object, effectiveVersion version.EffectiveVersion, scheme *runtime.Scheme) (schema.GroupVersion, error) {
   125          if example == nil || effectiveVersion == nil {
   126                  return binaryVersionOfResource, nil
   127          }
   128
   129          // Look up example in scheme to find all objects of the same Group-Kind
   130          // Use the highest priority version for that group-kind whose lifecycle window
   131          // includes the current emulation version.
   132          // If no version is found, use the binary version
   133          // (in this case the API should be disabled anyway)
   134          gvks, _, err := scheme.ObjectKinds(example)
   135          if err != nil {
   136                  return schema.GroupVersion{}, err
   137          }
   138
   139          var gvk schema.GroupVersionKind
   140          for _, item := range gvks {
   141                  if item.Group != binaryVersionOfResource.Group {
   142                          continue
   143                  }
   144
   145                  gvk = item
   146                  break
   147          }
   148
   149          if len(gvk.Kind) == 0 {
   150                  return schema.GroupVersion{}, fmt.Errorf("object %T has no GVKs registered in scheme", example)
   151          }
   152
   153          // VersionsForGroupKind returns versions in priority order
   154          versions := scheme.VersionsForGroupKind(schema.GroupKind{Group: gvk.Group, Kind: gvk.Kind})
   155
   156          compatibilityVersion := effectiveVersion.MinCompatibilityVersion()
   157
   158          for _, gv := range versions {
   159                  if gv.Version == runtime.APIVersionInternal {
   160                          continue
   161                  }
   162
   163                  gvk := schema.GroupVersionKind{
   164                          Group:   gv.Group,
   165                          Version: gv.Version,
   166                          Kind:    gvk.Kind,
   167                  }
   168
   169                  exampleOfGVK, err := scheme.New(gvk)
   170                  if err != nil {
   171                          return schema.GroupVersion{}, err
   172                  }
   173
   174                  // If it was introduced after current compatibility version, don't use it
   175                  // skip the introduced check for test when currentVersion is 0.0 to test all apis
   176                  if introduced, hasIntroduced := exampleOfGVK.(introducedInterface); hasIntroduced && (compatibilityVersion.Major() > 0 || compatibilityVersion.Minor() > 0) {
   177
   178                          // Skip versions that have a replacement.
   179                          // This can be used to override this storage version selection by
   180                          // marking a storage version has having a replacement and preventing a
   181                          // that storage version from being selected.
   182                          if _, hasReplacement := exampleOfGVK.(replacementInterface); hasReplacement {
   183                                  continue
   184                          }
   185                          // API resource lifecycles should be relative to k8s api version
   186                          majorIntroduced, minorIntroduced := introduced.APILifecycleIntroduced()
   187                          introducedVer := apimachineryversion.MajorMinor(uint(majorIntroduced), uint(minorIntroduced))
   188                          if introducedVer.GreaterThan(compatibilityVersion) {
   189                                  continue
   190                          }
   191                  }
   192
   193                  // versions is returned in priority order, so just use first result
   194                  return gvk.GroupVersion(), nil
   195          }
   196
   197          // Getting here means we're serving a version that is unknown to the
   198          // min-compatibility-version server.
   199          //
   200          // This is only expected to happen when serving an alpha API type due
   201          // to missing pre-release lifecycle information
   202          // (which doesn't happen by default), or when emulation-version and
   203          // min-compatibility-version are several versions apart so a beta or GA API
   204          // was being served which didn't exist at all in min-compatibility-version.
   205          //
   206          // In the alpha case - we do not support compatibility versioning of
   207          // alpha types and recommend users do not mix the two.
   208          // In the skip-level case - The version of apiserver we are retaining
   209          // compatibility with has no knowledge of the type,
   210          // so storing it in another type is no issue.
   211          return binaryVersionOfResource, nil
   212  }

