    38  // SetCommonEncodingVersion updates the CommonEncodingVersion and the AllEncodingVersionsEqual
    39  // condition based on the StorageVersions.
    40  func SetCommonEncodingVersion(sv *v1alpha1.StorageVersion) {
    41          var oldCommonEncodingVersion *string
    42          if sv.Status.CommonEncodingVersion != nil {
    43                  version := *sv.Status.CommonEncodingVersion
    44                  oldCommonEncodingVersion = &version
    45          }
    46          sv.Status.CommonEncodingVersion = nil
    47          if len(sv.Status.StorageVersions) != 0 {
    48                  firstVersion := sv.Status.StorageVersions[0].EncodingVersion
    49                  agreed := true
    50                  for _, ssv := range sv.Status.StorageVersions {
    51                          if ssv.EncodingVersion != firstVersion {
    52                                  agreed = false
    53                                  break
    54                          }
    55                  }
    56                  if agreed {
    57                          sv.Status.CommonEncodingVersion = &firstVersion
    58                  }
    59          }
    60
    61          condition := v1alpha1.StorageVersionCondition{
    62                  Type:               v1alpha1.AllEncodingVersionsEqual,
    63                  Status:             v1alpha1.ConditionFalse,
    64                  ObservedGeneration: sv.Generation,
    65                  LastTransitionTime: metav1.NewTime(time.Now()),
    66                  Reason:             "CommonEncodingVersionUnset",
    67                  Message:            "Common encoding version unset",
    68          }
    69          if sv.Status.CommonEncodingVersion != nil {
    70                  condition.Status = v1alpha1.ConditionTrue
    71                  condition.Reason = "CommonEncodingVersionSet"
    72                  condition.Message = "Common encoding version set"
    73          }
    74          forceTransition := false
    75          if oldCommonEncodingVersion != nil && sv.Status.CommonEncodingVersion != nil &&
    76                  *oldCommonEncodingVersion != *sv.Status.CommonEncodingVersion {
    77                  forceTransition = true
    78          }
    79          setStatusCondition(&sv.Status.Conditions, condition, forceTransition)
    80  }
    81
    82  func findStatusCondition(conditions []v1alpha1.StorageVersionCondition,
    83          conditionType v1alpha1.StorageVersionConditionType) *v1alpha1.StorageVersionCondition {
    84          for i := range conditions {
    85                  if conditions[i].Type == conditionType {
    86                          return &conditions[i]
    87                  }
    88          }
    89          return nil
    90  }
    91
    92  // setStatusCondition sets the corresponding condition in conditions to newCondition.
    93  // conditions must be non-nil.
    94  //  1. if the condition of the specified type already exists: all fields of the existing condition are updated to
    95  //     newCondition, LastTransitionTime is set to now if the new status differs from the old status
    96  //  2. if a condition of the specified type does not exist: LastTransitionTime is set to now() if unset,
    97  //     and newCondition is appended
    98  //
    99  // NOTE: forceTransition allows overwriting LastTransitionTime even when the status doesn't change.
   100  func setStatusCondition(conditions *[]v1alpha1.StorageVersionCondition, newCondition v1alpha1.StorageVersionCondition,
   101          forceTransition bool) {
   102          if conditions == nil {
   103                  return
   104          }
   105
   106          if newCondition.LastTransitionTime.IsZero() {
   107                  newCondition.LastTransitionTime = metav1.NewTime(time.Now())
   108          }
   109          existingCondition := findStatusCondition(*conditions, newCondition.Type)
   110          if existingCondition == nil {
   111                  *conditions = append(*conditions, newCondition)
   112                  return
   113          }
   114
   115          statusChanged := existingCondition.Status != newCondition.Status
   116          if statusChanged || forceTransition {
   117                  existingCondition.LastTransitionTime = newCondition.LastTransitionTime
   118          }
   119          existingCondition.Status = newCondition.Status
   120          existingCondition.Reason = newCondition.Reason
   121          existingCondition.Message = newCondition.Message
   122          existingCondition.ObservedGeneration = newCondition.ObservedGeneration
   123  }
