   125  // updateStorageVersionFor updates the storage version object for the resource.
   126  func updateStorageVersionFor(c Client, apiserverID string, gr schema.GroupResource, encodingVersion string, decodableVersions []string, servedVersions []string) error {
   127          retries := 3
   128          var retry int
   129          var err error
   130          for retry < retries {
   131                  err = singleUpdate(c, apiserverID, gr, encodingVersion, decodableVersions, servedVersions)
   132                  if err == nil {
   133                          return nil
   134                  }
   135                  if apierrors.IsAlreadyExists(err) || apierrors.IsConflict(err) {
   136                          time.Sleep(1 * time.Second)
   137                          continue
   138                  }
   139                  if err != nil {
   140                          klog.Errorf("retry %d, failed to update storage version for %v: %v", retry, gr, err)
   141                          retry++
   142                          time.Sleep(1 * time.Second)
   143                  }
   144          }
   145          return err
   146  }
   147
   148  func singleUpdate(c Client, apiserverID string, gr schema.GroupResource, encodingVersion string, decodableVersions []string, servedVersions []string) error {
   149          shouldCreate := false
   150          name := fmt.Sprintf("%s.%s", gr.Group, gr.Resource)
   151          sv, err := c.Get(context.TODO(), name, metav1.GetOptions{})
   152          if err != nil && !apierrors.IsNotFound(err) {
   153                  return err
   154          }
   155          if apierrors.IsNotFound(err) {
   156                  shouldCreate = true
   157                  sv = &v1alpha1.StorageVersion{}
   158                  sv.ObjectMeta.Name = name
   159          }
   160          updatedSV := localUpdateStorageVersion(sv, apiserverID, encodingVersion, decodableVersions, servedVersions)
   161          if shouldCreate {
   162                  createdSV, err := c.Create(context.TODO(), updatedSV, metav1.CreateOptions{})
   163                  if err != nil {
   164                          return err
