    70  func (p RESTStorageProvider) v1Storage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (map[string]rest.Storage, error) {
    71          storage := map[string]rest.Storage{}
    72
    73          // use a simple wrapper so that initialization order won't cause a nil getter
    74          var policyGetter rest.Getter
    75
    76          r, err := resolver.NewDiscoveryResourceResolver(p.DiscoveryClient)
    77          if err != nil {
    78                  return storage, err
    79          }
    80
    81          // validatingwebhookconfigurations
    82          if resource := "validatingwebhookconfigurations"; apiResourceConfigSource.ResourceEnabled(admissionregistrationv1.SchemeGroupVersion.WithResource(resource)) {
    83                  validatingStorage, err := validatingwebhookconfigurationstorage.NewREST(restOptionsGetter)
    84                  if err != nil {
    85                          return storage, err
    86                  }
    87                  storage[resource] = validatingStorage
    88          }
    89
    90          // mutatingwebhookconfigurations
    91          if resource := "mutatingwebhookconfigurations"; apiResourceConfigSource.ResourceEnabled(admissionregistrationv1.SchemeGroupVersion.WithResource(resource)) {
    92                  mutatingStorage, err := mutatingwebhookconfigurationstorage.NewREST(restOptionsGetter)
    93                  if err != nil {
    94                          return storage, err
    95                  }
    96                  storage[resource] = mutatingStorage
    97          }
    98
    99          // validatingadmissionpolicies
   100          if resource := "validatingadmissionpolicies"; apiResourceConfigSource.ResourceEnabled(admissionregistrationv1.SchemeGroupVersion.WithResource(resource)) {
   101                  policyStorage, policyStatusStorage, err := validatingadmissionpolicystorage.NewREST(restOptionsGetter, p.Authorizer, r)
   102                  if err != nil {
   103                          return storage, err
   104                  }
   105                  policyGetter = policyStorage
   106                  storage[resource] = policyStorage
   107                  storage[resource+"/status"] = policyStatusStorage
   108          }
   109
   110          // validatingadmissionpolicybindings
   111          if resource := "validatingadmissionpolicybindings"; apiResourceConfigSource.ResourceEnabled(admissionregistrationv1.SchemeGroupVersion.WithResource(resource)) {
   112                  policyBindingStorage, err := policybindingstorage.NewREST(restOptionsGetter, p.Authorizer, &policybindingstorage.DefaultPolicyGetter{Getter: policyGetter}, r)
   113                  if err != nil {
   114                          return storage, err
   115                  }
   116                  storage[resource] = policyBindingStorage
   117          }
   118
   119          return storage, nil
   120  }
